"},{"path":"src/coffee-ax.jsx","content":"import { useState, useEffect, useRef, forwardRef } from "react";
import {
  Coffee, ShoppingCart, Plus, Minus, Trash2, Calendar, MapPin, Lock,
  X, Check, Pencil, ChevronRight, Search, Clock, ChevronLeft,
  LayoutGrid, ListOrdered, CalendarDays, LogOut, Sun
} from "lucide-react";

/* ---------- constants ---------- */

const CATEGORIES = ["Coffee", "Snacks", "Fast Food"];
const ORDER_STATUSES = ["received", "preparing", "ready", "completed"];
const STATUS_LABEL = { received: "Received", preparing: "Preparing", ready: "Ready", completed: "Completed" };
const ADMIN_PIN = "4470";

const SEED_MENU = [
  { id: "m1", category: "Coffee", name: "Reef Break Espresso", price: 3.5, description: "Double shot, sharp and bright.", available: true },
  { id: "m2", category: "Coffee", name: "Salt Air Cold Brew", price: 4.75, description: "Steeped 18hrs, served over ice.", available: true },
  { id: "m3", category: "Coffee", name: "Coconut Horizon Latte", price: 5.25, description: "Espresso, steamed coconut milk.", available: true },
  { id: "m4", category: "Coffee", name: "Driftwood Mocha", price: 5.5, description: "Dark cacao, espresso, whole milk.", available: true },
  { id: "m5", category: "Snacks", name: "Mango Chili Skewer", price: 4.0, description: "Fresh mango, lime, tajin.", available: true },
  { id: "m6", category: "Snacks", name: "Toasted Coconut Bar", price: 3.25, description: "Oats, honey, toasted coconut.", available: true },
  { id: "m7", category: "Snacks", name: "Salted Plantain Chips", price: 2.75, description: "Fried to order, sea salt.", available: true },
  { id: "m8", category: "Fast Food", name: "Ax Fish Taco (2)", price: 8.5, description: "Grilled mahi, slaw, chipotle crema.", available: true },
  { id: "m9", category: "Fast Food", name: "Shack Burger", price: 9.5, description: "Beach-grilled beef, island sauce.", available: true },
  { id: "m10", category: "Fast Food", name: "Grilled Shrimp Bowl", price: 10.75, description: "Rice, shrimp, mango salsa.", available: true },
];

const SEED_EVENTS = [
  { id: "e1", title: "Sunrise Paddle & Pour-Over", date: nextDate(3), time: "6:30 AM", description: "Guided paddle out, coffee tasting on return.", spots: 20 },
  { id: "e2", title: "Bonfire Espresso Night", date: nextDate(9), time: "7:00 PM", description: "Live acoustic set, espresso cocktails.", spots: 40 },
  { id: "e3", title: "Beach Cleanup + Cold Brew", date: nextDate(16), time: "9:00 AM", description: "Cleanup crew gets free cold brew all day.", spots: 60 },
];

function nextDate(daysOut) {
  const d = new Date();
  d.setDate(d.getDate() + daysOut);
  return d.toISOString().slice(0, 10);
}
function fmtDate(iso) {
  const d = new Date(iso + "T00:00:00");
  return d.toLocaleDateString(undefined, { weekday: "short", month: "short", day: "numeric" });
}
function money(n) {
  return `$${Number(n).toFixed(2)}`;
}
function genId(prefix) {
  return `${prefix}${Date.now().toString(36)}${Math.floor(Math.random() * 900 + 100)}`;
}
function shortOrderId(n) {
  return `AX-${String(n).padStart(4, "0")}`;
}

/* ---------- storage helpers ---------- */

async function loadShared(key, seed) {
  try {
    // Use localStorage as fallback when window.storage is not available
    const stored = localStorage.getItem(key);
    if (stored) return JSON.parse(stored);
    localStorage.setItem(key, JSON.stringify(seed));
    return seed;
  } catch (e) {
    console.error("storage load failed", key, e);
    return seed;
  }
}

async function saveShared(key, value) {
  try {
    localStorage.setItem(key, JSON.stringify(value));
  } catch (e) {
    console.error("storage save failed", key, e);
  }
}

/* ---------- root ---------- */

export default function CoffeeAxApp() {
  const [loaded, setLoaded] = useState(false);
  const [menu, setMenu] = useState([]);
  const [events, setEvents] = useState([]);
  const [orders, setOrders] = useState([]);
  const [view, setView] = useState("customer"); // customer | admin
  const [orderCounter, setOrderCounter] = useState(1000);

  useEffect(() => {
    (async () => {
      const [m, ev, ord] = await Promise.all([
        loadShared("coffeeax-menu-items", SEED_MENU),
        loadShared("coffeeax-events", SEED_EVENTS),
        loadShared("coffeeax-orders", []),
      ]);
      setMenu(m);
      setEvents(ev);
      setOrders(ord);
      setOrderCounter(1000 + ord.length);
      setLoaded(true);
    })();
  }, []);

  async function persistMenu(next) {
    setMenu(next);
    await saveShared("coffeeax-menu-items", next);
  }
  async function persistEvents(next) {
    setEvents(next);
    await saveShared("coffeeax-events", next);
  }
  async function persistOrders(next) {
    setOrders(next);
    await saveShared("coffeeax-orders", next);
  }

  return (
    <div style={styles.appRoot}>
      <FontLoader />
      {!loaded ? (
        <LoadingScreen />
      ) : view === "customer" ? (
        <CustomerApp
          menu={menu}
          events={events}
          orders={orders}
          persistOrders={persistOrders}
          orderCounter={orderCounter}
          setOrderCounter={setOrderCounter}
          goAdmin={() => setView("admin")}
        />
      ) : (
        <AdminApp
          menu={menu}
          persistMenu={persistMenu}
          events={events}
          persistEvents={persistEvents}
          orders={orders}
          persistOrders={persistOrders}
          exit={() => setView("customer")}
        />
      )}
    </div>
  );
}

function LoadingScreen() {
  return (
    <div style={{ minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", background: "var(--sand)" }}>
      <div style={{ textAlign: "center" }}>
        <Coffee size={48} color="var(--teal)" style={{ marginBottom: 20 }} />
        <div style={{ fontFamily: "var(--font-display)", fontSize: 18, color: "var(--teal)" }}>
          LOADING COFFEE AX…
        </div>
      </div>
    </div>
  );
}

function FontLoader() {
  return (
    <link
      href="https://fonts.googleapis.com/css2?family=Georgia:wght@400;700&display=swap"
      rel="stylesheet"
    />
  );
}

const styles = {
  appRoot: {
    fontFamily: "var(--font-body)",
    background: "var(--sand)",
    color: "var(--ink)",
    minHeight: "100vh",
    width: "100%",
  },
};

/* ================= CUSTOMER APP ================= */

function CustomerApp({ menu, events, orders, persistOrders, orderCounter, setOrderCounter, goAdmin }) {
  const [cart, setCart] = useState([]);
  const [activeCat, setActiveCat] = useState("Coffee");
  const [cartOpen, setCartOpen] = useState(false);
  const [checkoutOpen, setCheckoutOpen] = useState(false);
  const [confirmedOrder, setConfirmedOrder] = useState(null);
  const [trackOpen, setTrackOpen] = useState(false);
  const menuRef = useRef(null);
  const eventsRef = useRef(null);

  function addToCart(item) {
    setCart((c) => {
      const found = c.find((i) => i.id === item.id);
      if (found) return c.map((i) => (i.id === item.id ? { ...i, qty: i.qty + 1 } : i));
      return [...c, { id: item.id, name: item.name, price: item.price, qty: 1 }];
    });
  }
  function changeQty(id, delta) {
    setCart((c) =>
      c
        .map((i) => (i.id === id ? { ...i, qty: i.qty + delta } : i))
        .filter((i) => i.qty > 0)
    );
  }
  function removeItem(id) {
    setCart((c) => c.filter((i) => i.id !== id));
  }
  const cartTotal = cart.reduce((s, i) => s + i.price * i.qty, 0);
  const cartCount = cart.reduce((s, i) => s + i.qty, 0);

  async function placeOrder(details) {
    const nextNum = orderCounter + 1;
    const order = {
      id: genId("ord_"),
      shortId: shortOrderId(nextNum),
      customerName: details.name,
      phone: details.phone,
      type: details.type,
      location: details.location,
      notes: details.notes,
      items: cart,
      total: cartTotal,
      status: "received",
      createdAt: new Date().toISOString(),
    };
    const next = [order, ...orders];
    await persistOrders(next);
    setOrderCounter(nextNum);
    setCart([]);
    setCheckoutOpen(false);
    setConfirmedOrder(order);
  }

  const scrollTo = (ref) => ref.current?.scrollIntoView({ behavior: "smooth", block: "start" });

  return (
    <div>
      <TopNav
        cartCount={cartCount}
        onCart={() => setCartOpen(true)}
        onMenu={() => scrollTo(menuRef)}
        onEvents={() => scrollTo(eventsRef)}
        onTrack={() => setTrackOpen(true)}
        onAdmin={goAdmin}
      />
      <Hero onOrderClick={() => scrollTo(menuRef)} />
      <MenuSection ref={menuRef} menu={menu} activeCat={activeCat} setActiveCat={setActiveCat} addToCart={addToCart} />
      <EventsSection ref={eventsRef} events={events} />
      <Footer />

      {cartOpen && (
        <CartDrawer
          cart={cart}
          total={cartTotal}
          onClose={() => setCartOpen(false)}
          changeQty={changeQty}
          removeItem={removeItem}
          onCheckout={() => {
            setCartOpen(false);
            setCheckoutOpen(true);
          }}
        />
      )}
      {checkoutOpen && (
        <CheckoutModal
          total={cartTotal}
          onClose={() => setCheckoutOpen(false)}
          onSubmit={placeOrder}
        />
      )}
      {confirmedOrder && (
        <ConfirmationModal order={confirmedOrder} onClose={() => setConfirmedOrder(null)} />
      )}
      {trackOpen && <TrackModal orders={orders} onClose={() => setTrackOpen(false)} />}
    </div>
  );
}

function TopNav({ cartCount, onCart, onMenu, onEvents, onTrack, onAdmin }) {
  return (
    <nav style={{ background: "var(--teal-deep)", padding: "14px 20px", display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 10, borderBottom: "2px solid var(--coral)" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
        <div style={{ width: 28, height: 28, background: "var(--coral)", clipPath: "polygon(0 0, 100% 0, 100% 70%, 70% 100%, 0 100%)", display: "flex", alignItems: "center", justifyContent: "center" }}>
          <Coffee size={15} color="var(--teal-deep)" />
        </div>
        <span style={{ fontFamily: "var(--font-display)", color: "var(--sand)", fontSize: 16 }}>
          COFFEE AX
        </span>
      </div>
      <div style={{ display: "flex", gap: 10, alignItems: "center", flexWrap: "wrap" }}>
        <NavBtn label="Menu" onClick={onMenu} icon={<LayoutGrid size={14} />} />
        <NavBtn label="Events" onClick={onEvents} icon={<CalendarDays size={14} />} />
        <NavBtn label="Track" onClick={onTrack} icon={<Clock size={14} />} />
        <button onClick={onAdmin} style={{ background: "transparent", border: "1px solid rgba(243,233,210,0.3)", color: "var(--sand)", borderRadius: 6, padding: "8px 12px", fontSize: 12.5, display: "flex", alignItems: "center", gap: 6, cursor: "pointer" }}>
          Admin
        </button>
        <button onClick={onCart} style={{ background: "var(--coral)", border: "none", color: "var(--teal-deep)", borderRadius: 6, padding: "8px 12px", fontSize: 13, fontWeight: 700, display: "flex", alignItems: "center", gap: 6, cursor: "pointer", position: "relative" }}>
          <ShoppingCart size={14} />
          Cart
          {cartCount > 0 && (
            <span style={{ background: "var(--teal-deep)", color: "var(--coral)", borderRadius: "50%", width: 18, height: 18, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 11, fontWeight: 700 }}>
              {cartCount}
            </span>
          )}
        </button>
      </div>
    </nav>
  );
}
function NavBtn({ label, onClick, icon }) {
  return (
    <button onClick={onClick} style={{ background: "transparent", border: "1px solid rgba(243,233,210,0.3)", color: "var(--sand)", borderRadius: 6, padding: "8px 12px", fontSize: 12.5, display: "flex", alignItems: "center", gap: 6, cursor: "pointer" }}>
      {icon}{label}
    </button>
  );
}

function Hero({ onOrderClick }) {
  return (
    <section style={{ background: "var(--teal-deep)", color: "var(--sand)", padding: "60px 20px", textAlign: "center" }}>
      <div style={{ maxWidth: 600, margin: "0 auto" }}>
        <div style={{ fontSize: 12, fontWeight: 700, letterSpacing: "0.08em", marginBottom: 12, color: "var(--coral)" }}>
           OPEN DAILY · 6AM – 8PM · SOUTH SHORE BEACH
        </div>
        <h1 style={{ fontFamily: "var(--font-display)", fontSize: 42, marginBottom: 16, lineHeight: 1.2 }}>
          Fresh cut,<br/>straight to the sand.
        </h1>
        <p style={{ fontSize: 16, marginBottom: 24, opacity: 0.9 }}>
          Coffee, snacks and fast food made to order — pick it up at the shack or have it dropped at your umbrella.
        </p>
        <button onClick={onOrderClick} style={{ background: "var(--coral)", color: "var(--teal-deep)", border: "none", borderRadius: 6, padding: "14px 28px", fontSize: 15, fontWeight: 700, cursor: "pointer" }}>
          ORDER NOW →
        </button>
      </div>
    </section>
  );
}

const MenuSection = forwardRef(function MenuSection({ menu, activeCat, setActiveCat, addToCart }, ref) {
  const items = menu.filter((m) => m.category === activeCat && m.available !== false);
  return (
    <section ref={ref} style={{ padding: "60px 20px", maxWidth: 1000, margin: "0 auto" }}>
      <SectionHeading eyebrow="HUNGRY?" title="What's Fresh Today" />
      <div style={{ display: "flex", gap: 10, marginBottom: 32, justifyContent: "center", flexWrap: "wrap" }}>
        {CATEGORIES.map((c) => (
          <button key={c} onClick={() => setActiveCat(c)} style={{
            padding: "10px 18px", borderRadius: 999, border: `2px solid var(--teal)`,
            background: activeCat === c ? "var(--teal)" : "transparent",
            color: activeCat === c ? "var(--sand)" : "var(--teal)",
            fontWeight: 700, fontSize: 14, cursor: "pointer"
          }}>{c}
        </button>
        ))}
      </div>
      {items.length === 0 ? (
        <div style={{ textAlign: "center", color: "var(--brown)", fontSize: 14 }}>
          Nothing in this category right now — check back soon.
        </div>
      ) : (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))", gap: 20 }}>
          {items.map((item) => (
            <div key={item.id} style={{ background: "#fff", borderRadius: 10, padding: 16, border: "1px solid rgba(139,111,71,0.15)" }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "start", marginBottom: 8 }}>
                <h3 style={{ margin: 0, fontSize: 16, color: "var(--ink)" }}>{item.name}</h3>
                <span style={{ fontFamily: "var(--font-mono)", fontWeight: 700, color: "var(--coral)" }}>{money(item.price)}</span>
              </div>
              <p style={{ fontSize: 13.5, color: "var(--brown)", marginBottom: 12, margin: 0 }}>{item.description}</p>
              <button onClick={() => addToCart(item)} style={{
                marginTop: 12, background: "var(--teal)", color: "var(--sand)", border: "none",
                borderRadius: 6, padding: "9px 0", fontWeight: 700, fontSize: 13.5,
                display: "flex", alignItems: "center", justifyContent: "center", gap: 6, width: "100%", cursor: "pointer"
              }}>
                <Plus size={14} /> Add to cart
              </button>
            </div>
          ))}
        </div>
      )}
    </section>
  );
});

const EventsSection = forwardRef(function EventsSection({ events }, ref) {
  const sorted = [...events].sort((a, b) => a.date.localeCompare(b.date));
  return (
    <section ref={ref} style={{ padding: "60px 20px", background: "var(--teal-deep)", color: "var(--sand)" }}>
      <div style={{ maxWidth: 1000, margin: "0 auto" }}>
        <SectionHeading eyebrow="COMMUNITY" title="Upcoming Events" dark />
        {sorted.length === 0 ? (
          <div style={{ textAlign: "center", opacity: 0.8, fontSize: 14 }}>
            No events scheduled — check back soon.
          </div>
        ) : (
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(300px, 1fr))", gap: 20 }}>
            {sorted.map((ev) => (
              <div key={ev.id} style={{ background: "rgba(243,233,210,0.1)", borderRadius: 10, padding: 20, border: "1px solid rgba(243,233,210,0.2)" }}>
                <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 8, fontSize: 12, color: "var(--coral)", fontWeight: 700 }}>
                   {fmtDate(ev.date)} · {ev.time}
                </div>
                <h3 style={{ margin: "0 0 8px 0", fontSize: 18, fontFamily: "var(--font-display)" }}>{ev.title}</h3>
                <p style={{ fontSize: 13.5, margin: 0, opacity: 0.9 }}>{ev.description}</p>
                {ev.spots ? (
                  <div style={{ marginTop: 12, fontSize: 12, opacity: 0.7, display: "flex", alignItems: "center", gap: 6 }}>
                     {ev.spots} spots · Coffee Ax beach shack
                  </div>
                ) : null}
              </div>
            ))}
          </div>
        )}
      </div>
    </section>
  );
});

function SectionHeading({ eyebrow, title, dark }) {
  return (
    <div style={{ marginBottom: 32, textAlign: "center" }}>
      <div style={{ fontSize: 11.5, fontWeight: 700, letterSpacing: "0.08em", textTransform: "uppercase", color: dark ? "var(--coral)" : "var(--teal)", marginBottom: 6 }}>{eyebrow}</div>
      <h2 style={{ fontFamily: "var(--font-display)", fontSize: 32, margin: 0, color: dark ? "var(--sand)" : "var(--ink)" }}>{title}</h2>
    </div>
  );
}

function Footer() {
  return (
    <footer style={{ padding: "30px 20px", background: "var(--ink)", color: "var(--sand)", textAlign: "center", fontSize: 13 }}>
      Coffee Ax · South Shore Beach · Coffee, snacks & fast food, made to order.
    </footer>
  );
}

/* ---------- cart / checkout / confirmation / tracking ---------- */

function Overlay({ children, onClose, align = "center" }) {
  return (
    <div onClick={onClose} style={{ position: "fixed", top: 0, left: 0, right: 0, bottom: 0, background: "rgba(0,0,0,0.5)", display: "flex", alignItems: align === "top" ? "flex-start" : "center", justifyContent: "center", padding: 20, zIndex: 1000 }}>
      <div onClick={(e) => e.stopPropagation()}>{children}</div>
    </div>
  );
}

function CartDrawer({ cart, total, onClose, changeQty, removeItem, onCheckout }) {
  return (
    <Overlay onClose={onClose} align="top">
      <div style={{ width: 380, maxWidth: "92vw", background: "var(--sand)", borderRadius: 12, padding: 24, maxHeight: "90vh", overflowY: "auto" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
          <h3 style={{ margin: 0, fontFamily: "var(--font-display)", fontSize: 17 }}>YOUR CART</h3>
          <button onClick={onClose} style={{ background: "none", border: "none", cursor: "pointer" }}><X size={20} /></button>
        </div>
        <div style={{ marginBottom: 14, borderTop: "1px solid rgba(139,111,71,0.15)", paddingTop: 14 }}>
          {cart.length === 0 ? (
