function AdminOrders({ orders, persistOrders }) {
  const todayRevenue = orders
    .filter((o) => o.createdAt.slice(0, 10) === new Date().toISOString().slice(0, 10))
    .reduce((s, o) => s + o.total, 0);

  async function updateStatus(id, status) {
    const next = orders.map((o) => (o.id === id ? { ...o, status } : o));
    await persistOrders(next);
  }
  async function clearAll() {
    if (confirm("Clear all order history? This cannot be undone.")) await persistOrders([]);
  }

  return (
    <div>
      <div style={{ display: "flex", gap: 14, marginBottom: 20, flexWrap: "wrap" }}>
        <StatCard label="Total orders" value={orders.length} />
        <StatCard label="Today's revenue" value={money(todayRevenue)} />
        <StatCard label="Awaiting pickup" value={orders.filter((o) => o.status !== "completed").length} />
      </div>
      {orders.length === 0 ? (
        <EmptyState text="No orders yet. New orders will show up here in real time." />
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          {orders.map((o) => (
            <div key={o.id} style={{ background: "#fff", borderRadius: 10, padding: 16, border: "1px solid rgba(139,111,71,0.15)" }}>
              <div style={{ display: "flex", justifyContent: "space-between", flexWrap: "wrap", gap: 8, marginBottom: 8 }}>
                <div>
                  <span style={{ fontFamily: "var(--font-mono)", fontWeight: 700, color: "var(--coral)" }}>{o.shortId}</span>
                  <span style={{ marginLeft: 10, fontWeight: 700 }}>{o.customerName}</span>
                  <span style={{ marginLeft: 8, color: "var(--brown)", fontSize: 12.5 }}>{o.phone}</span>
                </div>
                <select value={o.status} onChange={(e) => updateStatus(o.id, e.target.value)} style={{
                  ...inputStyle, width: "auto", padding: "6px 10px", fontSize: 12.5, fontWeight: 700, cursor: "pointer"
                }}>
                  {ORDER_STATUSES.map((s) => <option key={s} value={s}>{STATUS_LABEL[s]}</option>)}
                </select>
              </div>
              <div style={{ fontSize: 13, color: "var(--brown)", marginBottom: 6 }}>
                {o.type === "pickup" ? "Pickup" : `Beach delivery → ${o.location || "n/a"}`} · {new Date(o.createdAt).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}
              </div>
              <div style={{ fontSize: 13.5, marginBottom: 4 }}>
                {o.items.map((i) => `${i.qty}× ${i.name}`).join(", ")}
              </div>
              {o.notes && <div style={{ fontSize: 12.5, color: "var(--brown)", fontStyle: "italic" }}>Note: {o.notes}</div>}
              <div style={{ marginTop: 8, fontFamily: "var(--font-mono)", fontWeight: 700 }}>{money(o.total)}</div>
            </div>
          ))}
          <button onClick={clearAll} style={{ alignSelf: "flex-start", marginTop: 8, background: "none", border: "none", color: "var(--brown)", fontSize: 12, textDecoration: "underline", cursor: "pointer" }}>
            Clear order history
          </button>
        </div>
      )}
    </div>
  );
}
function StatCard({ label, value }) {
  return (
    <div style={{ background: "#fff", borderRadius: 10, padding: "14px 20px", minWidth: 140, border: "1px solid rgba(139,111,71,0.15)" }}>
      <div style={{ fontSize: 11.5, color: "var(--brown)", marginBottom: 4, textTransform: "uppercase", letterSpacing: "0.06em" }}>{label}</div>
      <div style={{ fontFamily: "var(--font-mono)", fontSize: 22, fontWeight: 700, color: "var(--teal)" }}>{value}</div>
