function EmptyState({ text }) {
  return <div style={{ background: "#fff", borderRadius: 10, padding: 30, textAlign: "center", color: "var(--brown)", border: "1px dashed rgba(139,111,71,0.3)" }}>{text}</div>;
}

function AdminMenu({ menu, persistMenu }) {
  const [editing, setEditing] = useState(null);
  async function save(item) {
    let next;
    if (item.id && menu.some((m) => m.id === item.id)) {
      next = menu.map((m) => (m.id === item.id ? item : m));
    } else {
      next = [...menu, { ...item, id: genId("m_") }];
    }
    await persistMenu(next);
    setEditing(null);
  }
  async function remove(id) {
    if (confirm("Remove this item from the menu?")) await persistMenu(menu.filter((m) => m.id !== id));
  }
  async function toggleAvailable(item) {
    await persistMenu(menu.map((m) => (m.id === item.id ? { ...m, available: !m.available } : m)));
  }

  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 16 }}>
        <div style={{ color: "var(--brown)", fontSize: 13.5 }}>{menu.length} items</div>
        <button onClick={() => setEditing("new")} style={{ background: "var(--teal)", color: "var(--sand)", border: "none", borderRadius: 6, padding: "9px 14px", fontWeight: 700, fontSize: 13, display: "flex", alignItems: "center", gap: 6, cursor: "pointer" }}>
          <Plus size={14} /> Add item
        </button>
      </div>
      {CATEGORIES.map((cat) => (
        <div key={cat} style={{ marginBottom: 22 }}>
          <h4 style={{ fontFamily: "var(--font-display)", fontSize: 14, color: "var(--teal)", marginBottom: 10 }}>{cat.toUpperCase()}</h4>
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {menu.filter((m) => m.category === cat).map((item) => (
              <div key={item.id} style={{ background: "#fff", borderRadius: 8, padding: 12, display: "flex", alignItems: "center", gap: 12, border: "1px solid rgba(139,111,71,0.15)", opacity: item.available === false ? 0.5 : 1 }}>
                <div style={{ flexGrow: 1 }}>
                  <div style={{ fontWeight: 700, fontSize: 14 }}>{item.name}</div>
                  <div style={{ fontSize: 12.5, color: "var(--brown)" }}>{item.description}</div>
                </div>
                <div style={{ fontFamily: "var(--font-mono)", fontWeight: 700 }}>{money(item.price)}</div>
                <button onClick={() => toggleAvailable(item)} style={{ fontSize: 11.5, padding: "5px 8px", borderRadius: 5, border: "1px solid var(--teal)", background: "transparent", color: "var(--teal)", cursor: "pointer" }}>
                  {item.available === false ? "Show" : "Hide"}
                </button>
                <button onClick={() => setEditing(item)} style={{ background: "none", border: "none", color: "var(--teal)", cursor: "pointer", padding: 4 }}><Pencil size={15} /></button>
                <button onClick={() => remove(item.id)} style={{ background: "none", border: "none", color: "var(--coral)", cursor: "pointer", padding: 4 }}><Trash2 size={15} /></button>
              </div>
            ))}
          </div>
        </div>
      ))}
      {editing && <MenuItemModal item={editing === "new" ? null : editing} onClose={() => setEditing(null)} onSave={save} />}
    </div>
  );
}
