        <Field label="Description"><textarea value={description} onChange={(e) => setDescription(e.target.value)} style={{ ...inputStyle, minHeight: 60 }} /></Field>
        <button disabled={!canSave} onClick={() => onSave({ id: item?.id, name, category, price: Number(price), description, available: item?.available !== false })} style={{
          width: "100%", background: canSave ? "var(--coral)" : "#ccc", color: "var(--teal-deep)", border: "none", borderRadius: 6, padding: "12px 0", fontWeight: 800, cursor: canSave ? "pointer" : "not-allowed"
