function AdminEvents({ events, persistEvents }) {
  const [editing, setEditing] = useState(null);
  async function save(ev) {
    let next;
    if (ev.id && events.some((e) => e.id === ev.id)) next = events.map((e) => (e.id === ev.id ? ev : e));
    else next = [...events, { ...ev, id: genId("e_") }];
    await persistEvents(next);
    setEditing(null);
  }
  async function remove(id) {
    if (confirm("Remove this event?")) await persistEvents(events.filter((e) => e.id !== id));
  }
  const sorted = [...events].sort((a, b) => a.date.localeCompare(b.date));
  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 16 }}>
        <div style={{ color: "var(--brown)", fontSize: 13.5 }}>{events.length} events</div>
        <button onClick={() => setEditing("new")} style={{ background: "var(--teal)", color: "var(--sand)", border: "none", borderRadius: 6, padding: "9px 14px", fontWeight: 700, fontSize: 13, display: "flex", alignItems: "center", gap: 6, cursor: "pointer" }}>
          <Plus size={14} /> Add event
        </button>
      </div>
      {sorted.length === 0 ? <EmptyState text="No events yet." /> : (
        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
          {sorted.map((ev) => (
            <div key={ev.id} style={{ background: "#fff", borderRadius: 8, padding: 12, display: "flex", alignItems: "center", gap: 12, border: "1px solid rgba(139,111,71,0.15)" }}>
              <div style={{ flexGrow: 1 }}>
                <div style={{ fontWeight: 700, fontSize: 14 }}>{ev.title}</div>
                <div style={{ fontSize: 12.5, color: "var(--brown)" }}>{fmtDate(ev.date)} · {ev.time} · {ev.description}</div>
              </div>
              <button onClick={() => setEditing(ev)} style={{ background: "none", border: "none", color: "var(--teal)", cursor: "pointer", padding: 4 }}><Pencil size={15} /></button>
              <button onClick={() => remove(ev.id)} style={{ background: "none", border: "none", color: "var(--coral)", cursor: "pointer", padding: 4 }}><Trash2 size={15} /></button>
            </div>
          ))}
        </div>
      )}
      {editing && <EventModal event={editing === "new" ? null : editing} onClose={() => setEditing(null)} onSave={save} />}
    </div>
  );
}
function EventModal({ event, onClose, onSave }) {
  const [title, setTitle] = useState(event?.title || "");
  const [date, setDate] = useState(event?.date || nextDate(1));
  const [time, setTime] = useState(event?.time || "9:00 AM");
  const [description, setDescription] = useState(event?.description || "");
  const [spots, setSpots] = useState(event?.spots ?? "");
  const canSave = title.trim() && date;
  return (
    <Overlay onClose={onClose}>
      <div style={{ width: 380, maxWidth: "92vw", background: "var(--sand)", borderRadius: 12, padding: 24 }}>
        <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 14 }}>
          <h3 style={{ margin: 0, fontFamily: "var(--font-display)", fontSize: 16 }}>{event ? "EDIT EVENT" : "NEW EVENT"}</h3>
          <button onClick={onClose} style={{ background: "none", border: "none", cursor: "pointer" }}><X size={18} /></button>
        </div>
        <Field label="Title"><input value={title} onChange={(e) => setTitle(e.target.value)} style={inputStyle} /></Field>
        <Field label="Date"><input type="date" value={date} onChange={(e) => setDate(e.target.value)} style={inputStyle} /></Field>
        <Field label="Time"><input value={time} onChange={(e) => setTime(e.target.value)} style={inputStyle} placeholder="e.g. 6:30 AM" /></Field>
        <Field label="Description"><textarea value={description} onChange={(e) => setDescription(e.target.value)} style={{ ...inputStyle, minHeight: 60 }} /></Field>
        <Field label="Spots (optional)"><input type="number" value={spots} onChange={(e) => setSpots(e.target.value)} style={inputStyle} /></Field>
        <button disabled={!canSave} onClick={() => onSave({ id: event?.id, title, date, time, description, spots: spots === "" ? null : Number(spots) })} style={{
          width: "100%", background: canSave ? "var(--coral)" : "#ccc", color: "var(--teal-deep)", border: "none", borderRadius: 6, padding: "12px 0", fontWeight: 800, cursor: canSave ? "pointer" : "not-allowed"
        }}>SAVE EVENT</button>
      </div>
    </Overlay>
  );
}
