const EventsSection = forwardRef(function EventsSection({ events }, ref) {
  const sorted = [...events].sort((a, b) => a.date.localeCompare(b.date));
  return (
    <div ref={ref} style={{ padding: "40px 20px", background: "#fff", maxWidth: 1040, margin: "0 auto" }}>
