function Overlay({ children, onClose, align = "center" }) {
  return (
    <div onClick={onClose} style={{ position: "fixed", top: 0, left: 0, right: 0, bottom: 0, background: "rgba(0,0,0,0.5)", display: "flex", alignItems: "center", justifyContent: align, zIndex: 1000 }}>
      <div onClick={(e) => e.stopPropagation()}>{children}</div>
    </div>
  );
}

function CartDrawer({ cart, total, onClose, changeQty, removeItem, onCheckout }) {
