            display: "flex", alignItems: "center", justifyContent: "center"
          }}>
            {i <= idx && <Check size={12} color="#fff" strokeWidth={3} />}
          </div>
          <div style={{ fontSize: 11, color: i <= idx ? "var(--ink)" : "var(--brown)", fontWeight: i === idx ? 700 : 500 }}>{STATUS_LABEL[s]}</div>
          {i < ORDER_STATUSES.length - 1 && (
            <div style={{ position: "absolute", top: 11, left: "60%", right: "-40%", height: 2, background: i < idx ? "var(--coral)" : "rgba(139,111,71,0.25)" }} />
          )}
        </div>
      ))}
    </div>
  );
}

