          </div>
          <input
            type="password"
            value={pin}
            onChange={(e) => { setPin(e.target.value); setError(""); }}
            onKeyDown={(e) => { if (e.key === "Enter") { pin === ADMIN_PIN ? setAuthed(true) : setError("Incorrect PIN."); } }}
            placeholder="Enter PIN"
            style={{ ...inputStyle, marginBottom: 10, letterSpacing: "0.2em" }}
          />
          {error && <div style={{ color: "var(--coral)", fontSize: 12.5, marginBottom: 10 }}>{error}</div>}
          <button onClick={() => (pin === ADMIN_PIN ? setAuthed(true) : setError("Incorrect PIN."))} style={{
            width: "100%", background: "var(--coral)", color: "var(--teal-deep)", border: "none",
            borderRadius: 6, padding: "12px 0", fontWeight: 800, marginBottom: 10, cursor: "pointer"
          }}>UNLOCK</button>
          <button onClick={exit} style={{ width: "100%", background: "none", border: "none", color: "var(--brown)", fontSize: 13, cursor: "pointer" }}>← Back to store</button>
