  return (
    <div style={{ minHeight: "100vh", background: "#F7F3E8" }}>
      <div style={{ background: "var(--teal-deep)", padding: "16px 20px", display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 10 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <div style={{ width: 28, height: 28, background: "var(--coral)", clipPath: "polygon(0 0, 100% 0, 100% 70%, 70% 100%, 0 100%)", display: "flex", alignItems: "center", justifyContent: "center" }}>
            <Coffee size={15} color="var(--teal-deep)" />
          </div>
          <span style={{ fontFamily: "var(--font-display)", color: "var(--sand)", fontSize: 16 }}>COFFEE AX · ADMIN</span>
        </div>
        <button onClick={exit} style={{ background: "transparent", border: "1px solid rgba(243,233,210,0.3)", color: "var(--sand)", borderRadius: 6, padding: "8px 12px", fontSize: 12.5, display: "flex", alignItems: "center", gap: 6, cursor: "pointer" }}>
          <LogOut size={13} /> Exit to store
        </button>
      </div>

      <div style={{ display: "flex", gap: 6, padding: "16px 20px 0", flexWrap: "wrap" }}>
        <TabBtn active={tab === "orders"} onClick={() => setTab("orders")} icon={<ListOrdered size={14} />} label={`Orders (${orders.length})`} />
        <TabBtn active={tab === "menu"} onClick={() => setTab("menu")} icon={<LayoutGrid size={14} />} label="Menu" />
        <TabBtn active={tab === "events"} onClick={() => setTab("events")} icon={<CalendarDays size={14} />} label="Events" />
      </div>

      <div style={{ padding: 20, maxWidth: 1040, margin: "0 auto" }}>
        {tab === "orders" && <AdminOrders orders={orders} persistOrders={persistOrders} />}
        {tab === "menu" && <AdminMenu menu={menu} persistMenu={persistMenu} />}
