function TabBtn({ active, onClick, icon, label }) {
  return (
    <button onClick={onClick} style={{
      padding: "10px 16px", borderRadius: "8px 8px 0 0", border: "none",
      background: active ? "#F7F3E8" : "transparent", color: active ? "var(--ink)" : "var(--brown)",
      fontWeight: 700, fontSize: 13.5, display: "flex", alignItems: "center", gap: 6,
      borderBottom: active ? "3px solid var(--coral)" : "3px solid transparent", cursor: "pointer"
    }}>{icon}{label}</button>
  );
}

function AdminOrders({ orders, persistOrders }) {
  const todayRevenue = orders
    .filter((o) => o.createdAt.slice(0, 10) === new Date().toISOString().slice(0, 10))
    .reduce((s, o) => s + o.total, 0);

  async function updateStatus(id, status) {
    const next = orders.map((o) => (o.id === id ? { ...o, status } : o));
    await persistOrders(next);
  }
  async function clearAll() {
    if (confirm("Clear all order history? This cannot be undone.")) await persistOrders([]);
  }

  return (
    <div>
      <div style={{ display: "flex", gap: 14, marginBottom: 20, flexWrap: "wrap" }}>
        <StatCard label="Total orders" value={orders.length} />
        <StatCard label="Today's revenue" value={money(todayRevenue)} />
        <StatCard label="Awaiting pickup" value={orders.filter((o) => o.status !== "completed").length} />
      </div>
      {orders.length === 0 ? (
        <EmptyState text="No orders yet. New orders will show up here in real time." />
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          {orders.map((o) => (
            <div key={o.id} style={{ background: "#fff", borderRadius: 10, padding: 16, border: "1px solid rgba(139,111,71,0.15)" }}>
              <div style={{ display: "flex", justifyContent: "space-between", flexWrap: "wrap", gap: 8, marginBottom: 8 }}>
                <div>
                  <span style={{ fontFamily: "var(--font-mono)", fontWeight: 700, color: "var(--coral)" }}>{o.shortId}</span>
                  <span style={{ marginLeft: 10, fontWeight: 700 }}>{o.customerName}</span>
                  <span style={{ marginLeft: 8, color: "var(--brown)", fontSize: 12.5 }}>{o.phone}</span>
                </div>
                <select value={o.status} onChange={(e) => updateStatus(o.id, e.target.value)} style={{
                  ...inputStyle, width: "auto", padding: "6px 10px", fontSize: 12.5, fontWeight: 700
                }}>
                  {ORDER_STATUSES.map((s) => <option key={s} value={s}>{STATUS_LABEL[s]}</option>)}
                </select>
              </div>
              <div style={{ fontSize: 13, color: "var(--brown)", marginBottom: 6 }}>
                {o.type === "pickup" ? "Pickup" : `Beach delivery → ${o.location || "n/a"}`} · {new Date(o.createdAt).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}
              </div>
              <div style={{ fontSize: 13.5, marginBottom: 4 }}>
                {o.items.map((i) => `${i.qty}× ${i.name}`).join(", ")}
              </div>
              {o.notes && <div style={{ fontSize: 12.5, color: "var(--brown)", fontStyle: "italic" }}>Note: {o.notes}</div>}
              <div style={{ marginTop: 8, fontFamily: "var(--font-mono)", fontWeight: 700 }}>{money(o.total)}</div>
            </div>
          ))}
          <button onClick={clearAll} style={{ alignSelf: "flex-start", marginTop: 8, background: "none", border: "none", color: "var(--brown)", fontSize: 12, textDecoration: "underline", cursor: "pointer" }}>
            Clear order history
          </button>
        </div>
      )}
    </div>
  );
}
function StatCard({ label, value }) {
  return (
    <div style={{ background: "#fff", borderRadius: 10, padding: "14px 20px", minWidth: 140, border: "1px solid rgba(139,111,71,0.15)" }}>
      <div style={{ fontSize: 11.5, color: "var(--brown)", marginBottom: 4, textTransform: "uppercase", letterSpacing: "0.06em" }}>{label}</div>
      <div style={{ fontFamily: "var(--font-mono)", fontSize: 22, fontWeight: 700, color: "var(--teal)" }}>{value}</div>
    </div>
  );
}
function EmptyState({ text }) {
  return <div style={{ background: "#fff", borderRadius: 10, padding: 30, textAlign: "center", color: "var(--brown)", border: "1px dashed rgba(139,111,71,0.3)" }}>{text}</div>;
}

function AdminMenu({ menu, persistMenu }) {
  const [editing, setEditing] = useState(null);
  async function save(item) {
    let next;
    if (item.id && menu.some((m) => m.id === item.id)) {
      next = menu.map((m) => (m.id === item.id ? item : m));
    } else {
      next = [...menu, { ...item, id: genId("m_") }];
    }
    await persistMenu(next);
    setEditing(null);
  }
  async function remove(id) {
    if (confirm("Remove this item from the menu?")) await persistMenu(menu.filter((m) => m.id !== id));
  }
  async function toggleAvailable(item) {
    await persistMenu(menu.map((m) => (m.id === item.id ? { ...m, available: !m.available } : m)));
  }

  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 16 }}>
        <div style={{ color: "var(--brown)", fontSize: 13.5 }}>{menu.length} items</div>
        <button onClick={() => setEditing("new")} style={{ background: "var(--teal)", color: "var(--sand)", border: "none", borderRadius: 6, padding: "9px 14px", fontWeight: 700, fontSize: 13, display: "flex", alignItems: "center", gap: 6, cursor: "pointer" }}>
          <Plus size={14} /> Add item
        </button>
      </div>
      {CATEGORIES.map((cat) => (
        <div key={cat} style={{ marginBottom: 22 }}>
          <h4 style={{ fontFamily: "var(--font-display)", fontSize: 14, color: "var(--teal)", marginBottom: 10 }}>{cat.toUpperCase()}</h4>
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {menu.filter((m) => m.category === cat).map((item) => (
              <div key={item.id} style={{ background: "#fff", borderRadius: 8, padding: 12, display: "flex", alignItems: "center", gap: 12, border: "1px solid rgba(139,111,71,0.15)", opacity: item.available === false ? 0.5 : 1 }}>
                <div style={{ flexGrow: 1 }}>
                  <div style={{ fontWeight: 700, fontSize: 14 }}>{item.name}</div>
                  <div style={{ fontSize: 12.5, color: "var(--brown)" }}>{item.description}</div>
                </div>
                <div style={{ fontFamily: "var(--font-mono)", fontWeight: 700 }}>{money(item.price)}</div>
                <button onClick={() => toggleAvailable(item)} style={{ fontSize: 11.5, padding: "5px 8px", borderRadius: 5, border: "1px solid var(--teal)", background: "transparent", color: "var(--teal)", cursor: "pointer" }}>
                  {item.available === false ? "Show" : "Hide"}
                </button>
                <button onClick={() => setEditing(item)} style={{ background: "none", border: "none", color: "var(--teal)", cursor: "pointer" }}><Pencil size={15} /></button>
